    ) AS v(id, customer_id, status, total_amount, currency, notes)
)
INSERT INTO dbo.orders (id, customer_id, status, total_amount, currency, notes, created_at, updated_at)
SELECT
    s.id,
    s.customer_id,
    s.status,
    s.total_amount,
    s.currency,
    s.notes,
    GETUTCDATE(),
    GETUTCDATE()
FROM order_seed s
WHERE NOT EXISTS (
    SELECT 1
    FROM dbo.orders o
    WHERE o.id = s.id
);
GO

